parameters.jsCode:
// Build the Slack Block Kit payload from the RAG draft + original ticket context.
const webhook = $('Webhook').first().json.body || {};
const draft = $input.first().json.generated_draft || '';
const email = webhook.sender_email || 'unknown@customer.com';
const query = webhook.text || '';
const subject = webhook.subject || '';
const queryShort = query.slice(0, 900); // Slack button 'value' is capped at 2000 chars; carry a safe excerpt of the real email to the escalation ticket

const body = {
  channel: 'customer-ops-triage',
  text: 'New high-confidence triage draft ready for review',
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: '📥 NEW HIGH-CONFIDENCE TRIAGE DRAFT', emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: '*Customer:* ' + email } },
    { type: 'section', text: { type: 'mrkdwn', text: '*Original Query:*\n>' + query } },
    { type: 'section', text: { type: 'mrkdwn', text: '*AI Generated Response:*\n```' + draft + '```' } },
    { type: 'actions', elements: [
      { type: 'button', text: { type: 'plain_text', text: 'Approve & Send', emoji: true }, style: 'primary', action_id: 'approve_triage_send', value: JSON.stringify({ email: email, draft: draft, subject: subject, query: queryShort }) },
      { type: 'button', text: { type: 'plain_text', text: 'Reject & Escalate', emoji: true }, style: 'danger', action_id: 'reject_triage_escalate', value: JSON.stringify({ email: email, draft: draft, subject: subject, query: queryShort }) }
    ] }
  ]
};

return [{ json: { slackBody: body } }];

// Slack posts interactive events as an x-www-form-urlencoded 'payload' field.
const raw = $input.first().json.body ? $input.first().json.body.payload : undefined;
const payload = typeof raw === 'string' ? JSON.parse(raw) : (raw || {});
const action = (payload.actions && payload.actions[0]) ? payload.actions[0] : {};

let meta = {};
try { meta = JSON.parse(action.value); } catch (e) { meta = {}; }

return [{ json: {
  action_id: action.action_id || '',
  response_url: payload.response_url || '',
  user: payload.user ? payload.user.username : '',
  customer_email: meta.email || '',
  draft: meta.draft || '',
  validatedDraftText: meta.draft || '',
  subject: meta.subject || '',
  original_email: meta.query || ''
} }];

